package servlets;
import db.DBConnection; import javax.servlet.*; import javax.servlet.annotation.WebServlet; import javax.servlet.http.*; import java.io.*; import java.sql.*; import java.util.*;
@WebServlet("/my-events") public class MyEventsServlet extends HttpServlet { protected void doGet(HttpServletRequest req,HttpServletResponse resp)throws ServletException,IOException{HttpSession s=req.getSession(false);if(s==null||s.getAttribute("userId")==null){resp.sendRedirect("login.jsp");return;}List<Map<String,Object>> rows=new ArrayList<>();String q="SELECT e.Event_ID,e.Title,e.Event_Date,e.Location,c.Name Category,s.Status,s.Waitlist_Position,s.Signed_Up_At FROM Signups s JOIN Events e ON e.Event_ID=s.Event_ID JOIN Categories c ON c.Category_ID=e.Category_ID WHERE s.Student_ID=? ORDER BY e.Event_Date DESC";try(Connection con=DBConnection.getConnection();PreparedStatement p=con.prepareStatement(q)){p.setInt(1,(Integer)s.getAttribute("userId"));try(ResultSet r=p.executeQuery()){while(r.next()){Map<String,Object>m=new HashMap<>();for(String k:new String[]{"Event_ID","Title","Event_Date","Location","Category","Status","Waitlist_Position","Signed_Up_At"})m.put(k,r.getObject(k));rows.add(m);}}}catch(SQLException e){throw new ServletException(e);}req.setAttribute("events",rows);req.getRequestDispatcher("my-events.jsp").forward(req,resp);}}
